# ─── LIVE PRICE FETCH ────────────────────────────────────────────────────────
@st.cache_data(ttl=300)
def fetch_live_prices(symbols):
    prices = {}
    BATCH = 50
    for i in range(0, len(symbols), BATCH):
        batch = symbols[i:i+BATCH]
        tickers = [s + ".NS" for s in batch]
        try:
            raw = yf.download(tickers, period="1d", interval="1d",
                              auto_adjust=True, progress=False, threads=True)
            if raw.empty:
                continue
            closes = raw["Close"].iloc[-1] if isinstance(raw.columns, pd.MultiIndex) else raw.iloc[-1]
            for sym in batch:
                t = sym + ".NS"
                try:
                    val = closes.get(t) if hasattr(closes, "get") else closes[t]
                    if val is not None and not np.isnan(float(val)):
                        prices[sym] = round(float(val), 2)
                except:
                    pass
        except:
            pass
        time.sleep(0.2)
    return prices

# ─── FILTER & FETCH ──────────────────────────────────────────────────────────
candidates = [
    s for s in STOCK_DATA
    if s["score"]  >= min_score
    and s["rr"]    >= min_rr
    and s["tier"]  in tiers
    and (not above200_only or s["above_200"])
]

with st.spinner(f"Fetching live prices for {len(candidates)} stocks..."):
    live = fetch_live_prices([s["sym"] for s in candidates])

st.success(f"✓ {len(live)} prices loaded — {datetime.now().strftime('%H:%M:%S')} IST")

# ─── COMPUTE DISTANCES ───────────────────────────────────────────────────────
rows = []
for s in candidates:
    sym = s["sym"]
    if sym not in live:
        continue
    price     = live[sym]
    cb        = s["crash_buy"]
    dist_pct  = (price / cb - 1) * 100
    l2 = cb * (1 - s["avg_drop"] * 0.15 / 100)
    l3 = cb * (1 - s["avg_drop"] * 0.30 / 100)
    rows.append({
        **s,
        "live":       price,
        "dist_pct":   round(dist_pct, 2),
        "l2":         round(l2, 2),
        "l3":         round(l3, 2),
        "sl":         round(l3 * 0.95, 2),
        "upside_pct": round((s["rot_target"] / price - 1) * 100, 1),
    })

rows.sort(key=lambda x: x["dist_pct"])

in_zone    = [r for r in rows if -3 <= r["dist_pct"] <= 3]
near_zone  = [r for r in rows if  3 <  r["dist_pct"] <= prox]
below_zone = [r for r in rows if      r["dist_pct"]  < -3]

# ─── METRICS ─────────────────────────────────────────────────────────────────
c1, c2, c3 = st.columns(3)
c1.metric("🟢 In Zone ±3%", len(in_zone))
c2.metric("🟡 Approaching",  len(near_zone))
c3.metric("🔵 Below Zone",   len(below_zone))
st.divider()

# ─── CARD RENDERER ───────────────────────────────────────────────────────────
def render_card(r, mode="zone"):
    dist = r["dist_pct"]
    if mode == "below":
        css, dc, icon = "card-red",    "red",    "🔵"
    elif mode == "zone":
        css, dc, icon = "card-green",  "green",  "🟢"
    else:
        css, dc, icon = "card-yellow", "yellow", "🟡"
    sign  = "+" if dist > 0 else ""
    above = "↑200DMA" if r["above_200"] else "↓200DMA"
    days  = int(r.get("drop_days", 20))
    live_fmt  = f"{r['live']:,.2f}"
    cb_fmt    = f"{r['crash_buy']:,.2f}"
    tgt_fmt   = f"{r['rot_target']:,.2f}"
    l2_fmt    = f"{r['l2']:,.2f}"
    l3_fmt    = f"{r['l3']:,.2f}"
    sl_fmt    = f"{r['sl']:,.2f}"
    st.markdown(f"""
<div class="card {css}">
  <div><span class="sym">{icon} {r["sym"]}</span>
       <span class="tier">{r["tier"]}</span>
       <span class="tier" style="background:#1a2a40;color:#94a3b8">{above}</span></div>
  <div class="dist {dc}">{sign}{dist:.2f}% to crash buy</div>
  <div class="meta">Score {r["score"]} · R:R {r["rr"]} · Win {int(r["win_pct"])}% · {r["rot_yr"]}×/yr</div>
  <div class="price-row">
    <div><div class="price-label">LIVE</div><div class="price-val">₹{live_fmt}</div></div>
    <div><div class="price-label">CRASH BUY L1</div><div class="price-val">₹{cb_fmt}</div></div>
    <div><div class="price-label">TARGET</div><div class="price-val" style="color:#22c55e">₹{tgt_fmt}</div></div>
    <div><div class="price-label">UPSIDE</div><div class="price-val" style="color:#22c55e">+{r["upside_pct"]}%</div></div>
  </div>
  <div class="price-row" style="margin-top:6px">
    <div><div class="price-label">L2 (35%)</div><div class="price-val" style="font-size:.8rem">₹{l2_fmt}</div></div>
    <div><div class="price-label">L3 (25%)</div><div class="price-val" style="font-size:.8rem">₹{l3_fmt}</div></div>
    <div><div class="price-label">HARD SL</div><div class="price-val" style="font-size:.8rem;color:#ef4444">₹{sl_fmt}</div></div>
    <div><div class="price-label">AVG DAYS</div><div class="price-val" style="font-size:.8rem">~{days}d</div></div>
  </div>
</div>""", unsafe_allow_html=True)

# ── 🟢 IN ZONE ───────────────────────────────────────────────────────────────
if in_zone:
    st.markdown(f"### 🟢 In Buy Zone — ±3% of crash buy ({len(in_zone)})")
    st.caption("Price is at the GTC level — verify your orders are active")
    for r in in_zone[:20]:
        render_card(r, mode="zone")
else:
    st.info("No stocks within ±3% of crash buy zone right now.")

# ── 🟡 APPROACHING ───────────────────────────────────────────────────────────
if near_zone:
    st.markdown(f"### 🟡 Approaching — within {prox}% above crash buy ({len(near_zone)})")
    st.caption("Set GTC orders now so you don't miss the entry")
    for r in near_zone[:25]:
        render_card(r, mode="approach")

# ── 🔵 BELOW ZONE ────────────────────────────────────────────────────────────
with st.expander(f"🔵 Below Zone — crashed past crash buy ({len(below_zone)})"):
    st.caption("Fallen below crash buy. Deep value candidates — recalculate levels first.")
    for r in below_zone[:30]:
        render_card(r, mode="below")

